Implementasi Observer Pattern menggunakan Python `abc` untuk enforce interface yang ketat. Kode ini dirancang untuk maintainability dan keamanan data.

```python
from abc import ABC, abstractmethod
from typing import List, Any, Optional
import weakref

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        """Triggered when subject state changes."""
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class ConcreteSubject(Subject):
    def __init__(self):
        # Gunakan weakref untuk mencegah memory leaks jika observer tidak di-unregister
        self._observers: List[weakref.ref] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        if observer not in [ref() for ref in self._observers]:
            self._observers.append(weakref.ref(observer))

    def detach(self, observer: Observer) -> None:
        self._observers = [ref for ref in self._observers if ref() is not observer]

    def notify(self) -> None:
        # Clean up dead references saat notify
        for ref in self._observers[:]:
            observer = ref()
            if observer:
                observer.update(self)
            else:
                self._observers.remove(ref)

    def set_state(self, state: Any) -> None:
        # VALIDASI KEAMANAN: Sanitasi state sebelum broadcast
        # Mencegah objek berbahaya atau data tidak terverifikasi menyebar ke observer
        if not self._validate_state(state):
            raise ValueError("Invalid state data detected")

        self._state = state
        self.notify()

    def _validate_state(self, state: Any) -> bool:
        # Implementasi logika validasi spesifik aplikasi
        return True

    def get_state(self) -> Any:
        return self._state

class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self._name = name

    def update(self, subject: Subject) -> None:
        state = subject.get_state()
        # Pastikan processing state aman dari sisi observer
        print(f"[{self._name}] State Updated: {state}")

# Usage Example
if __name__ == "__main__":
    subject = ConcreteSubject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogSystem")

    subject.attach(obs1)
    subject.attach(obs2)

    # Data diverifikasi sebelum didistribusikan
    subject.set_state({"event": "login_attempt", "status": "success"})
```

**Catatan Teknis:**
1.  **Memory Management:** Menggunakan `weakref` untuk mencegah circular reference yang menyebabkan memory leaks pada aplikasi long-running.
2.  **Defensive Security:** Method `_validate_state` wajib diimplementasikan untuk memastikan tidak ada data malicious (seperti payload RCE/SQLi) yang lolos ke observer.
3.  **Type Hinting:** Wajib digunakan untuk menjaga integritas kode dan memudahkan static analysis.
